import { Component, Input, OnChanges, SimpleChanges, ViewChild } from '@angular/core';
import { CommonModule } from '@angular/common';
import { MatIconModule } from '@angular/material/icon';
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';
import { MatPaginatorModule, MatPaginator, PageEvent } from '@angular/material/paginator';
import { TransactionService } from '../../../core/services/transaction.service';
import { Transaction } from '../../../core/models/transaction.model';

@Component({
  selector: 'app-transaction-list',
  standalone: true,
  imports: [CommonModule, MatIconModule, MatProgressSpinnerModule, MatPaginatorModule],
  templateUrl: './transaction-list.component.html',
})
export class TransactionListComponent implements OnChanges {
  @Input() accountId!: number;
  @Input() refreshTrigger = 0;

  @ViewChild(MatPaginator) paginator?: MatPaginator;

  transactions: Transaction[] = [];
  loading = false;
  error = '';
  currentPage = 0;
  pageSize = 10;
  totalElements = 0;

  constructor(private transactionService: TransactionService) {}

  ngOnChanges(changes: SimpleChanges): void {
    if (changes['accountId']) {
      this.currentPage = 0;
      this.paginator?.firstPage();
    }
    if (changes['accountId'] || changes['refreshTrigger']) {
      this.load();
    }
  }

  load(): void {
    this.loading = true;
    this.error = '';
    this.transactionService.getByAccount(this.accountId, this.currentPage, this.pageSize).subscribe({
      next: (res) => {
        this.transactions = res._embedded?.transactions ?? [];
        this.totalElements = res.page?.totalElements ?? 0;
        this.loading = false;
      },
      error: (err: Error) => {
        this.error = err.message;
        this.loading = false;
      },
    });
  }

  onPageChange(event: PageEvent): void {
    this.currentPage = event.pageIndex;
    this.pageSize = event.pageSize;
    this.load();
  }

  formatCurrency(value: number): string {
    return new Intl.NumberFormat('es-CO', {
      style: 'currency', currency: 'COP', minimumFractionDigits: 2,
    }).format(value);
  }

  formatDate(dateStr?: string): string {
    if (!dateStr) return '';
    return new Date(dateStr).toLocaleString('es-CO', {
      day: '2-digit', month: 'short', year: 'numeric',
      hour: '2-digit', minute: '2-digit',
    });
  }
}
<div class="tx-list">
  @if (loading) {
    <div class="loading-state">
      <mat-spinner diameter="16"></mat-spinner>
      <span>Cargando movimientos...</span>
    </div>
  } @else if (error) {
    <p style="color:#ef4444;font-size:12px">Error cargando transacciones.</p>
  } @else if (transactions.length === 0) {
    <p class="no-tx">Sin movimientos registrados en esta página.</p>
  } @else {
    @for (tx of transactions; track tx.id) {
      <div class="tx-item">
        <div class="tx-left">
          <div class="tx-icon-wrap" [class]="tx.transactionType === 'DEPOSIT' ? 'deposit' : 'withdrawal'">
            <mat-icon>{{ tx.transactionType === 'DEPOSIT' ? 'south_west' : 'north_east' }}</mat-icon>
          </div>
          <div class="tx-info">
            <div class="tx-type">{{ tx.transactionType === 'DEPOSIT' ? 'Consignación' : 'Retiro' }}</div>
            @if (tx.description) {
              <div class="tx-desc">{{ tx.description }}</div>
            }
            <div class="tx-date">{{ formatDate(tx.createdAt) }}</div>
          </div>
        </div>
        <div class="tx-right">
          <div class="tx-amount" [class]="tx.transactionType === 'DEPOSIT' ? 'deposit' : 'withdrawal'">
            {{ tx.transactionType === 'DEPOSIT' ? '+' : '-' }}{{ formatCurrency(tx.amount) }}
          </div>
          <div class="tx-balance">Saldo: {{ formatCurrency(tx.balanceAfter) }}</div>
        </div>
      </div>
    }
  }

  @if (!loading && totalElements > 0) {
    <mat-paginator
      [length]="totalElements"
      [pageSize]="pageSize"
      [pageSizeOptions]="[5, 10, 20]"
      [pageIndex]="currentPage"
      (page)="onPageChange($event)"
      showFirstLastButtons
      class="tx-paginator">
    </mat-paginator>
  }
</div>
